import React, { useState, useEffect } from "react";
import { useParams, useNavigate } from "react-router-dom";
import { Card, CardContent, TextField, Button, Typography, MenuItem } from "@mui/material";
import axios from "axios";

const EditMedicine = () => {
    const { id } = useParams();
    const navigate = useNavigate();
    const [medicine, setMedicine] = useState({
        code: "",
        name: "",
        type: "",
        price: "",
        unit: "",
        description: ""
    });

    useEffect(() => {
        axios.get(`/api/medicines/${id}`)
            .then((response) => {
                setMedicine(response.data);
            })
            .catch((error) => {
                console.error("Error fetching medicine:", error);
            });
    }, [id]);

    const handleChange = (e) => {
        setMedicine({ ...medicine, [e.target.name]: e.target.value });
    };

    const handleSubmit = (e) => {
        e.preventDefault();
        axios.put(`/api/medicines/${id}`, medicine)
            .then(() => {
                navigate("/medicines");
            })
            .catch((error) => {
                console.error("Error updating medicine:", error);
            });
    };

    return (
        <Card sx={{ maxWidth: 600, margin: "auto", mt: 5, p: 3 }}>
            <CardContent>
                <Typography variant="h5" gutterBottom>
                    Chỉnh sửa thuốc
                </Typography>
                <form onSubmit={handleSubmit}>
                    <TextField
                        fullWidth
                        label="Mã thuốc"
                        name="code"
                        value={medicine.code}
                        onChange={handleChange}
                        margin="normal"
                        required
                    />
                    <TextField
                        fullWidth
                        label="Tên thuốc"
                        name="name"
                        value={medicine.name}
                        onChange={handleChange}
                        margin="normal"
                        required
                    />
                    <TextField
                        fullWidth
                        select
                        label="Loại thuốc"
                        name="type"
                        value={medicine.type}
                        onChange={handleChange}
                        margin="normal"
                        required
                    >
                        <MenuItem value="Viên">Viên</MenuItem>
                        <MenuItem value="Dung dịch">Dung dịch</MenuItem>
                        <MenuItem value="Bột">Bột</MenuItem>
                    </TextField>
                    <TextField
                        fullWidth
                        label="Giá"
                        name="price"
                        type="number"
                        value={medicine.price}
                        onChange={handleChange}
                        margin="normal"
                        required
                    />
                    <TextField
                        fullWidth
                        label="Đơn vị tính"
                        name="unit"
                        value={medicine.unit}
                        onChange={handleChange}
                        margin="normal"
                        required
                    />
                    <TextField
                        fullWidth
                        label="Mô tả"
                        name="description"
                        value={medicine.description}
                        onChange={handleChange}
                        margin="normal"
                        multiline
                        rows={3}
                    />
                    <Button type="submit" variant="contained" color="primary" sx={{ mt: 2, mr: 2 }}>
                        Lưu lại
                    </Button>
                    <Button variant="outlined" color="secondary" sx={{ mt: 2 }} onClick={() => navigate("/medicines")}>
                        Quay lại
                    </Button>
                </form>
            </CardContent>
        </Card>
    );
};

export default EditMedicine;
